// ===== Quản lý dữ liệu =====
function initData() {
  // Kiểm tra và xóa dữ liệu với STK cũ
  const raw = localStorage.getItem('mmo_data_v2');
  if (raw) {
    try {
      const data = JSON.parse(raw);
      // Nếu phát hiện STK cũ (089964571), xóa dữ liệu
      if (data.users && data.users.some(u => u.bankAccount === '089964571' || u.bankName === 'LE HOANG VIET')) {
        localStorage.removeItem('mmo_data_v2');
      }
    } catch (e) {}
  }
  
  const updatedRaw = localStorage.getItem('mmo_data_v2');
  if (!updatedRaw) {
    localStorage.setItem('mmo_data_v2', JSON.stringify(INITIAL_DATA));
  } else {
    try {
      const existing = JSON.parse(updatedRaw);
      if (!existing.settings || existing.settings.nextProductId < 270 || existing.settings.nextCategoryId < 15) {
        localStorage.setItem('mmo_data_v2', JSON.stringify(INITIAL_DATA));
      } else {
        // Patch dữ liệu cũ thiếu field mới
        let changed = false;
        if (!existing.notifications) { existing.notifications = []; changed = true; }
        if (!existing.settings.nextNotificationId) { existing.settings.nextNotificationId = 1; changed = true; }
        if (existing.users) {
          existing.users.forEach(u => {
            if (u.balance === undefined) { u.balance = 0; changed = true; }
            if (!u.orderHistory) { u.orderHistory = []; changed = true; }
          });
        }
        if (changed) localStorage.setItem('mmo_data_v2', JSON.stringify(existing));
      }
    } catch(e) {
      localStorage.setItem('mmo_data_v2', JSON.stringify(INITIAL_DATA));
    }
  }
}
function getData() {
  const raw = localStorage.getItem('mmo_data_v2');
  return raw ? JSON.parse(raw) : INITIAL_DATA;
}
function saveData(data) {
  localStorage.setItem('mmo_data_v2', JSON.stringify(data));
}
function resetData() {
  localStorage.setItem('mmo_data_v2', JSON.stringify(INITIAL_DATA));
  return INITIAL_DATA;
}
initData();
